+using Coypu;
+using OpenQA.Selenium;
+using ProjectSight.Tests.BrowserPages.Bases;
+using ProjectSight.Tests.BrowserPages.Helpers;
+
+namespace ProjectSight.Tests.BrowserPages.Controls
+{
+    public class WebViewer : BrowserAndElementAware
+    {
+        private readonly PrologTable.Types _tableType;
+
+        public WebViewer(BrowserAgent browser, ElementScope parentScope, PrologTable.Types recordType) : base(browser, parentScope)
+        {
+            _tableType = recordType;
+        }
+
+        #region Locators
+
+        private ShadowDomRoot _WebViewer => new ShadowDomRoot(m_scope.FindCss("apryse-webviewer"));
+        private SeleniumElementScope _PDFContainer => _WebViewer.FindId("pageContainer1");
+        private SeleniumElementScope _Canvas => _WebViewer.FindCss("canvas.auxiliary");
+        private AddLinkPopup _AddLinkPopup => new AddLinkPopup(m_browser, m_scope.FindCss("add-link-popup"), isSingleSelect: true);
+        public WebViewerSearchPanel SearchPanel => new WebViewerSearchPanel(Browser, _WebViewer);
+        public WebViewerCommentsPanel CommentsPanel => new WebViewerCommentsPanel(Browser, _WebViewer);
+        public ViewerDimensions ViewerDimensions
+        {
+            get
+            {
+                return new ViewerDimensions
+                {
+                    Height = int.Parse(_Canvas["height"]),
+                    Width = int.Parse(_Canvas["width"]),
+                    PageRotation = int.Parse(_Canvas["data-page-rotation"])
+                };
+            }
+        }
+
+        /// <summary>
+        /// Used to locate the annotation tools such as cloud, draw, rectangle, etc. In most of the viewers, it will be
+        /// the WebViewer itself, but in others (such as drawings), it may be a parent of the WebViewer. In the DrawingFDEF,
+        /// the annotation tools exist outside the WebViewer shadow root, so they are being located from m_scope
+        /// </summary>
+        private SeleniumElementScope _AnnotationToolsParent
+        {
+            get
+            {
+                switch (_tableType)
+                {
+                    case PrologTable.Types.Drawing:
+                        return new SeleniumElementScope(m_scope);
+                    default:
+                        return _WebViewer;
+                }
+            }
+        }
+
+        public SeleniumElementScope AnnotationPopup
+        {
+            get
+            {
+                switch (_tableType)
+                {
+                    case PrologTable.Types.Drawing:
+                        return new SeleniumElementScope(m_scope.FindCss("annotation-edit-dialog"));
+                    default:
+                        return _WebViewer.FindCss(".Popup.AnnotationPopup.open.react-draggable");
+                }
+            }
+        }
+
+        public SeleniumElementScope AnnotationLinkButton
+        {
+            get
+            {
+                switch (_tableType)
+                {
+                    case PrologTable.Types.Drawing:
+                        return new SeleniumElementScope(m_scope.FindCss("button[data-gainsight='annotation-edit-dialog-link']"));
+                    default:
+                        return _WebViewer.FindCss("button[data-element='psLinkButton']");
+                }
+            }
+        }
+
+        public SeleniumElementScope AnnotationDeleteButton
+        {
+            get
+            {
+                switch (_tableType)
+                {
+                    case PrologTable.Types.Drawing:
+                        return new SeleniumElementScope(m_scope.FindCss("button[data-gainsight='annotation-edit-dialog-delete']"));
+                    default:
+                        return _WebViewer.FindCss("button[data-element='annotationDeleteButton']");
+                }
+            }
+        }
+
+
+        #endregion Locators
+
+        #region Methods
+
+        public bool IsOnPage()
+        {
+            return _WebViewer.FindCss(".hacc.canvas1").Exists(timeout: SeleniumTimeout.LONG);
+        }
+
+        public void ClickPointOnPDF(int x, int y, int waitAfterClick = 0)
+        {
+            var viewerControl = (WebElement)_PDFContainer.Native;
+            var driver = (WebDriver)viewerControl.WrappedDriver;
+
+            MouseHelper.MoveAndClickMouse(driver, viewerControl, x, y);
+
+            if (waitAfterClick > 0)
+            {
+                Thread.Sleep(waitAfterClick);
+            }
+        }
+
+        public void DragOnPDF(int x1, int y1, int x2, int y2, int deltaX = 1, int deltaY = 1)
+        {
+            var viewerControl = (WebElement)_PDFContainer.Native;
+            var driver = (WebDriver)viewerControl.WrappedDriver;
+
+            MouseHelper.MoveAndClickMouse(driver, viewerControl, x1, y1);
+            MouseHelper.DragMouse(driver, viewerControl, x1, y1, x2, y2, deltaX, deltaY);
+        }
+
+        public void DrawRegion(int x1, int y1, int x2, int y2, int deltaX = 1, int deltaY = 1)
+        {
+            var viewerControl = (WebElement)_PDFContainer.Native;
+            var driver = (WebDriver)viewerControl.WrappedDriver;
+
+            MouseHelper.DragMouse(driver, viewerControl, x1, y1, x2, y2, deltaX, deltaY);
+            MouseHelper.DoubleClick(driver, viewerControl);
+        }
+
+        /// <summary>
+        /// Adds an annotation of any non-multi-point-click type to the PDF.
+        /// </summary>
+        public void AddAnnotation(string annotationGroup, string annotationType = null, int xOffset = 0, int yOffset = 0, int x2Offset = 0, int y2Offset = 0, int deltaX = 1, int deltaY = 1)
+        {
+            const int INITIAL_DRAW_POINT = 100;
+
+            this.ChooseAnnotationType(annotationGroup, annotationType);
+
+            if (x2Offset == 0 && y2Offset == 0)
+            {
+                // xOffset and yOffset parameters are used if multiple annotations to be created during the same test run, so they don't overlap completely
+                this.DrawRegion(INITIAL_DRAW_POINT + xOffset, INITIAL_DRAW_POINT + yOffset, 400 + xOffset, 400 + yOffset, 100, 100);
+            }
+            else
+            {
+                this.DrawRegion(xOffset, yOffset, x2Offset, y2Offset, deltaX, deltaY);
+            }
+        }
+
+        /// <summary>
+        /// Adds a multi-point annotation to the PDF.
+        /// </summary>
+        public void AddPolyLineAnnotation(AnnotationsPath[] paths, string annotationGroup, string annotationType = null)
+        {
+            if (paths.Length < 2)
+            {
+                throw new ArgumentException("2 or more paths are required for poly line annotation");
+            }
+
+            this.ChooseAnnotationType(annotationGroup, annotationType);
+
+            var viewerControl = (WebElement)_PDFContainer.Native;
+            var driver = (WebDriver)viewerControl.WrappedDriver;
+
+            MouseHelper.MultiPointsMouseClick(driver, viewerControl, paths);
+            MouseHelper.DoubleClick(driver, viewerControl);
+        }
+
+        /// <summary>
+        /// Links an existing open annotation to a record.
+        /// </summary>
+        public void LinkAnnotationToRecord(string recordType, string recordSelector = null, bool isForCreate = false)
+        {
+            if (!isForCreate && string.IsNullOrEmpty(recordSelector))
+            {
+                throw new ArgumentException("recordSelector is required for linking to an existing record");
+            }
+
+            AnnotationLinkButton.Click();
+
+            if (isForCreate)
+            {
+                _AddLinkPopup.ClickRecordCreateOption(recordType);
+            }
+            else
+            {
+                _AddLinkPopup.AddRecordLink(recordType, recordSelector);
+            }
+        }
+
+        public void DeleteAnnotation()
+        {
+            AnnotationDeleteButton.Click();
+        }
+
+        public SeleniumElementScope GetWebViewerElement(string cssSelector)
+        {
+            return _WebViewer.FindCss(cssSelector);
+        }
+
+        private string GetAnnotationGroupCss(string annotationGroup)
+        {
+            switch (_tableType)
+            {
+                case PrologTable.Types.Drawing:
+                    return $"li > div[title='{annotationGroup}']";
+
+                default:
+                    return $"button[aria-label='{annotationGroup}']";
+            }
+        }
+
+        private string GetAnnotationTypeCss(string annotationType)
+        {
+            switch (_tableType)
+            {
+                case PrologTable.Types.Drawing:
+                    return $".markup-group li[title='{annotationType}']";
+
+                default:
+                    return $"button[aria-label='{annotationType}']";
+            }
+        }
+
+        private void ChooseAnnotationType(string annotationGroup, string annotationType = null)
+        {
+            // select annotation group
+            _AnnotationToolsParent.FindCss(this.GetAnnotationGroupCss(annotationGroup)).Click();
+
+            // select annotation type to annotate with if specified
+            if (!string.IsNullOrEmpty(annotationType))
+            {
+                var annotationTypeOption = _AnnotationToolsParent.FindCss(this.GetAnnotationTypeCss(annotationType));
+                var isNotSelected = !annotationTypeOption.ClassList.Contains("active");
+
+                // always click annotation type in drawings, otherwise click if not already selected
+                if (_tableType == PrologTable.Types.Drawing || isNotSelected)
+                {
+                    annotationTypeOption.Click();
+                }
+            }
+        }
+
+        #endregion Methods
+    }
+
+    public class AnnotationsPath
+    {
+        public int X { get; private set; }
+        public int Y { get; private set; }
+
+        public AnnotationsPath(int x, int y)
+        {
+            X = x;
+            Y = y;
+        }
+    }
+
+    public class ViewerDimensions
+    {
+        public int Height { get; set; }
+        public int Width { get; set; }
+        public int PageRotation { get; set; }
+    }
+}

