+using Coypu;
+using ProjectSight.Tests.BrowserPages.Contracts;
+using ProjectSight.Tests.BrowserPages.Controls;
+using ProjectSight.Tests.BrowserPages.Helpers;
+
+namespace ProjectSight.Tests.BrowserPages.Bases
+{
+    public abstract class WebViewerFullDefBase<T, TABS> : FullDefBase<T, TABS>, IWebViewer
+        where T : PrologRecordBase
+        where TABS : FullDefBase.BaseDEFTabs
+    {
+        protected WebViewerFullDefBase(BrowserAgent browser, ElementScope scope) : base(browser, scope)
+        {
+        }
+
+        protected WebViewerFullDefBase() : base()
+        {
+        }
+
+        #region Locators
+
+        private WebViewer _WebViewer => new WebViewer(m_browser, m_scope, TableType);
+
+        public WebViewerSearchPanel SearchPanel => _WebViewer.SearchPanel;
+        public WebViewerCommentsPanel CommentsPanel => _WebViewer.CommentsPanel;
+        public ViewerDimensions ViewerDimensions => _WebViewer.ViewerDimensions;
+        public SeleniumElementScope AnnotationPopup => _WebViewer.AnnotationPopup;
+        public SeleniumElementScope AnnotationLinkButton => _WebViewer.AnnotationLinkButton;
+        public SeleniumElementScope AnnotationDeleteButton => _WebViewer.AnnotationDeleteButton;
+
+        #endregion Locators
+
+        #region Methods
+
+        public bool WaitForPageToLoad()
+        {
+            return _WebViewer.IsOnPage();
+        }
+
+        public void ClickPointOnPDF(int x, int y, int waitAfterClick = 0)
+        {
+            _WebViewer.ClickPointOnPDF(x, y, waitAfterClick);
+        }
+
+        public void DragOnPDF(int x1, int y1, int x2, int y2, int deltaX = 1, int deltaY = 1)
+        {
+            _WebViewer.DragOnPDF(x1, y1, x2, y2, deltaX, deltaY);
+        }
+
+        public void DrawRegion(int x1, int y1, int x2, int y2, int deltaX = 1, int deltaY = 1)
+        {
+            _WebViewer.DrawRegion(x1, y1, x2, y2, deltaX, deltaY);
+        }
+
+        public void AddAnnotation(string annotationGroup, string annotationType = null, int xOffset = 0, int yOffset = 0, int x2Offset = 0, int y2Offset = 0, int deltaX = 1, int deltaY = 1)
+        {
+            _WebViewer.AddAnnotation(annotationGroup, annotationType, xOffset, yOffset, x2Offset, y2Offset, deltaX, deltaY);
+        }
+
+        public void AddPolyLineAnnotation(AnnotationsPath[] paths, string annotationGroup, string annotationType = null)
+        {
+            _WebViewer.AddPolyLineAnnotation(paths, annotationGroup, annotationType);
+        }
+
+        public void LinkAnnotationToRecord(string recordType, string recordSelector = null, bool isForCreate = false)
+        {
+            _WebViewer.LinkAnnotationToRecord(recordType, recordSelector, isForCreate);
+        }
+
+        public void DeleteAnnotation()
+        {
+            _WebViewer.DeleteAnnotation();
+        }
+
+        protected SeleniumElementScope GetWebViewerElement(string cssSelector)
+        {
+            return _WebViewer.GetWebViewerElement(cssSelector);
+        }
+
+        #endregion Methods
+    }
+}
